;">            <i class="bi bi-shield-slash-fill text-danger display-1 mb-4"></i>            <h1 class="h3 fw-bold mb-3">Edição Desativada</h1>            <p class="text-body-secondary mb-4">A edição de arquivos Markdown externos está desativada nas configurações administrativas do sistema.</p>            <a href="index.php" class="btn btn-outline-secondary btn-sm"><i class="bi bi-arrow-left"></i> Voltar ao Portal</a>        </div>    </body>    </html>    <?php    exit;}// Handle markdown savingif ($_SERVER['REQUEST_METHOD'] === 'POST') {    $markdownContent = $_POST['content'] ?? '';    file_put_contents($mdFile, $markdownContent);    header('Location: editor.php?file=' . urlencode($targetFile) . '&saved=true');    exit;}Security::applyHeaders();$markdownContent = file_exists($mdFile) ? file_get_contents($mdFile) : '';$bootstrapCss = 'https://cdn.jsdelivr.net/npm/bootstrap@5.3.3/dist/css/bootstrap.min.css';$bootstrapJs = 'https://cdn.jsdelivr.net/npm/bootstrap@5.3.3/dist/js/bootstrap.bundle.min.js';?><!doctype html><html lang="pt-BR" data-module="carex"><head>    <meta charset="utf-8">    <meta name="viewport" content="width=device-width, initial-scale=1">    <title>CAREX | Editor de Documentação</title>    <link href="public/assets/favicon.png" rel="icon" type="image/png">    <link href="https://fonts.googleapis.com/css2?family=Outfit:wght@400;600;800&family=Plus+Jakarta+Sans:wght@400;500;700&display=swap" rel="stylesheet">    <link href="<?= Security::e($bootstrapCss) ?>" rel="stylesheet" integrity="sha384-QWTKZyjpPEjISv5WaRU9OFeRpok6YctnYmDr5pNlyT2bRjXh0JMhjY6hW+ALEwIH" crossorigin="anonymous">    <link rel="stylesheet" href="https://cdn.jsdelivr.net/npm/bootstrap-icons@1.11.3/font/bootstrap-icons.min.css">    <script src="../assets/js/theme-switcher.js"></script>    <style>        :root {            --accent-blue: #00a7e8;            --accent-purple: #8b5cf6;            --card-bg: rgba(30, 41, 59, 0.45);            --card-border: rgba(255, 255, 255, 0.08);        }        body {            background: linear-gradient(135deg, #0f172a 0%, #1e1b4b 50%, #020617 100%);            color: #f8fafc;            font-family: 'Plus Jakarta Sans', sans-serif;            min-height: 100vh;        }        .header-brand {            font-family: 'Outfit', sans-serif;            font-weight: 800;            background: linear-gradient(to right, #ffffff, var(--accent-blue));            -webkit-background-clip: text;            -webkit-text-fill-color: transparent;        }        .editor-card {            background: var(--card-bg);            border: 1px solid var(--card-border);            border-radius: 1.25rem;            backdrop-filter: blur(20px);            box-shadow: 0 20px 50px rgba(0, 0, 0, 0.3);        }        .preview-area {            background: rgba(15, 23, 42, 0.3);            border: 1px solid var(--card-border);            border-radius: 0.75rem;            padding: 2rem;            min-height: 400px;            color: #e2e8f0;            line-height: 1.7;        }        .preview-area h1, .preview-area h2, .preview-area h3 {            font-family: 'Outfit', sans-serif;            font-weight: 700;            color: #ffffff;            margin-top: 1.5rem;            margin-bottom: 1rem;        }        .preview-area h1 {            border-bottom: 1px solid var(--card-border);            padding-bottom: 0.5rem;        }        .preview-area code {            background: rgba(255, 255, 255, 0.08);            padding: 0.2rem 0.4rem;            border-radius: 0.25rem;            font-size: 0.9em;            color: var(--accent-blue);        }        .preview-area pre {            background: rgba(15, 23, 42, 0.8);            border: 1px solid var(--card-border);            padding: 1.25rem;            border-radius: 0.5rem;            overflow-x: auto;        }        .preview-area pre code {            background: transparent;            padding: 0;            color: #f8fafc;        }        .editor-textarea {            background: #0f172a;            border: 1px solid var(--card-border);            color: #f8fafc;            font-family: 'Fira Code', 'Courier New', Courier, monospace;            font-size: 0.95rem;            line-height: 1.5;            resize: vertical;            border-radius: 0.75rem;            padding: 1.25rem;            min-height: 400px;        }        .editor-textarea:focus {            background: #0f172a;            color: #f8fafc;            border-color: var(--accent-blue);            box-shadow: 0 0 0 0.25rem rgba(0, 167, 232, 0.2);        }        .mode-btn {            border: 1px solid var(--card-border);            background: rgba(255, 255, 255, 0.03);            color: #e2e8f0;            transition: all 0.2s ease;        }        .mode-btn.active {            background: var(--accent-blue);            border-color: var(--accent-blue);            color: #ffffff;            font-weight: 600;        }    </style>    <link href="../assets/css/style.css" rel="stylesheet"></head><body>    <header class="border-bottom border-white-50 border-opacity-10 py-3 mb-4 bg-dark bg-opacity-25 backdrop-blur">        <div class="container d-flex justify-content-between align-items-center">            <a href="index.php" class="d-flex align-items-center gap-2 text-decoration-none">                <img src="public/assets/favicon.png" alt="Logo" style="height: 28px;">                <span class="header-brand fs-4">CAREX</span>            </a>            <a href="index.php" class="btn btn-sm btn-outline-secondary d-flex align-items-center gap-1">                <i class="bi bi-arrow-left"></i> Voltar ao Portal            </a>        </div>    </header>    <main class="container py-3">        <?php if (isset($_GET['saved']) && $_GET['saved'] === 'true'): ?>            <div class="alert alert-success alert-dismissible fade show mb-4 border-success-subtle shadow" role="alert">                <i class="bi bi-check-circle-fill me-2"></i> Documento salvo com sucesso!                <button type="button" class="btn-close" data-bs-dismiss="alert" aria-label="Close"></button>            </div>        <?php endif; ?>        <div class="editor-card p-4">            <div class="d-flex flex-wrap justify-content-between align-items-center gap-3 mb-4">                <div>                    <h1 class="h4 mb-0 fw-bold">Documentação Dinâmica</h1>                    <span class="text-secondary small">Editando <?= Security::e($targetFile) ?>.md</span>                </div>                <div class="d-flex gap-2">                    <div class="btn-group btn-group-sm" role="group" aria-label="Modo de Visualização">                        <button type="button" id="btnPreview" class="btn mode-btn active"><i class="bi bi-eye-fill me-1"></i> Visualizar</button>                        <button type="button" id="btnEdit" class="btn mode-btn"><i class="bi bi-pencil-fill me-1"></i> Editar</button>                    </div>                    <button type="submit" form="editorForm" class="btn btn-sm btn-primary d-flex align-items-center gap-1 shadow-sm">                        <i class="bi bi-cloud-arrow-up-fill"></i> Salvar Alterações                    </button>                </div>            </div>            <!-- Form for Markdown content -->            <form id="editorForm" method="POST" action="editor.php">                <input type="hidden" name="file" value="<?= Security::e($targetFile) ?>">                <textarea id="markdownEditor" name="content" class="form-control editor-textarea" hidden><?= Security::e($markdownContent) ?></textarea>            </form>            <!-- Rendered Output -->            <div id="markdownPreview" class="preview-area"></div>        </div>    </main>    <!-- Marked JS for Markdown Rendering -->    <script src="https://cdn.jsdelivr.net/npm/marked/marked.min.js"></script>    <script src="<?= Security::e($bootstrapJs) ?>" integrity="sha384-YvpcrYf0tY3lHB60NNkmXc5s9fDVZLESaAA55NDzOxhy9GkcIdslK1eN7N6jIeHz" crossorigin="anonymous"></script>    <script>        const editor = document.getElementById('markdownEditor');        const preview = document.getElementById('markdownPreview');        const btnPreview = document.getElementById('btnPreview');        const btnEdit = document.getElementById('btnEdit');        function updatePreview() {            preview.innerHTML = marked.parse(editor.value);        }        // Initialize preview        updatePreview();        // Mode toggling        btnPreview.addEventListener('click', () => {            btnPreview.classList.add('active');            btnEdit.classList.remove('active');            editor.hidden = true;            preview.hidden = false;            updatePreview();        });        btnEdit.addEventListener('click', () => {            btnEdit.classList.add('active');            btnPreview.classList.remove('active');            editor.hidden = false;            preview.hidden = true;        });    </script></body></html>